local CS = CS

local WxCustomAdapter = CardEHT.WxCustomAdapter
---@class LWxHelper
local LWxHelper = LxClass("LWxHelper", nil)

local MINI_GAME_PLATFORM = {
    WeChat = "WXMiniGame",
    DouYin = "DouYinMiniGame",
    Bili = "BiliMiniGame"
}

local _platform = nil
local _wxPlatform = nil
local _isMiniGame = nil
function LWxHelper._InnerGetPlatform()
    if not _platform then
        _platform = LNativeHelper.GetPlatform()
    end
    return _platform
end

---@region 平台判断相关
function LWxHelper.IsWxPlatform()
    local pf = LWxHelper._InnerGetPlatform()
    if pf == "WXMiniGame" then
        return true
    end
end

---@region 平台判断相关
function LWxHelper.IsDouYinPlatform()
    local pf = LWxHelper._InnerGetPlatform()
    if pf == "DouYinMiniGame" then
        return true
    end
end

---@region 平台判断相关
function LWxHelper.IsBiliPlatform()
    local pf = LWxHelper._InnerGetPlatform()
    if pf == "BiliMiniGame" then
        return true
    end
end

function LWxHelper.IsMiniGamePlatform()
    if _isMiniGame == nil then
        local pf = LWxHelper._InnerGetPlatform()
        if pf == "DouYinMiniGame" or pf == "WXMiniGame" or pf == "BiliMiniGame" then
            _isMiniGame = true
        else
            _isMiniGame = false
        end
    end

    return _isMiniGame
end


function LWxHelper.GetWxPlatform()
    if not _wxPlatform then
        _wxPlatform = WxCustomAdapter.WxGetPlatform()
    end
    return _wxPlatform
end

function LWxHelper.IsInIos()
    if LWxHelper.IsMiniGamePlatform() then
        local pf = LWxHelper.GetWxPlatform()
        return  pf == "ios"
    end
    return false
end

function LWxHelper.IsInAndroid()
    if LWxHelper.IsMiniGamePlatform() then
        local pf = LWxHelper.GetWxPlatform()
        return  pf == "android"
    end
    return false
end
---@endregion 平台判断相关

