--设备内存值
function LWxHelper.WxMemorySize()
    return WxCustomAdapter.WxMemorySize()
end

local isLowM

--是否低内存
function LWxHelper.IsLowMemory()
    if isLowM == nil then
        isLowM = false
        local memorySize = LWxHelper.WxMemorySize()
        if memorySize ~= nil and memorySize ~= "" then
            --gprint("IsLowMemory memorySize : "..memorySize)
            memorySize = tonumber(memorySize) / 1024 --微信返回的是M
            if memorySize < 3 then
                isLowM = true
            end
        end
    end
    return isLowM
end

